+/**
+ * Result of diagnosing delta parsing issues in a thread.
+ * Does not attempt to compile — only analyzes delta block parsing.
+ */
+interface DiagnoseResult {
+  threadId: string;
+  messageCount: number;
+  deltaMessageCount: number;
+  summary: {
+    healthy: number;
+    issues: number;
+  };
+  deltas: {
